const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};
const secret = $env.N8N_HEADER_AUTH_VALUE;
const received = headers['x-videomill-auth'] || headers['x-viranode-secret'];

if (secret && received !== secret) {
  return [{ json: { error: 'Unauthorized', authorized: false } }];
}

const item = body;
console.log('📥 mottatt:', { video_id: item.video_id, user_id: item.user_id, topic: item.topic });

return [{ json: { ...item, authorized: true } }];

const item = $input.first().json;

const prompt = `Lag et viral video-manus om: ${item.topic || 'interessant tema'}.

Krav:
- title (string)
- description (string)
- hashtags (array)
- scenes (array med: narration, visual_description, duration_seconds, search_keywords)

${item.language ? '- Språk: ' + item.language : ''}
${item.target_audience ? '- Målgruppe: ' + item.target_audience : ''}
${item.platform ? '- Platform: ' + item.platform : ''}

Lag 3-5 scener, hver 5-10 sekunder. Ekte innhold, ingen placeholders.`;

return [{ json: { ...item, prompt } }];

