const content = $input.first().json.choices?.[0]?.message?.content || '{}';
let script = {};

try { script = JSON.parse(content); } catch {
  try {
    const m = content.match(/\[[\s\S]*\]/);
    if (m) script = JSON.parse(m[0]);
  } catch { script = { title: 'Video', scenes: [] }; }
}

const item = $input.first().json;
console.log('✅ Manus:', { title: script.title, scener: script.scenes?.length || 0 });

if (!script.scenes || !Array.isArray(script.scenes) || script.scenes.length === 0) {
  console.log('⚠️ Bruker default scener');
  script.scenes = [
    { narration: 'Velkommen til denne videoen', visual_description: 'Intro', duration_seconds: 5, search_keywords: ['intro'] },
    { narration: 'Hovedinnholdet presenteres her', visual_description: 'Hovedinnhold', duration_seconds: 8, search_keywords: ['content'] },
    { narration: 'Takk for at du så på!', visual_description: 'Outro', duration_seconds: 5, search_keywords: ['outro'] }
  ];
}

return [{ json: { ...script, ...item } }];

const item = items[0].json;

const voiceId = item.voice_id || '';
const lang = item.language || 'nb';

const voiceMap = {
  nb: { id: 'CwhRBW8gmZU9ZJ8eXARK', name: 'Pernille' },
  en: { id: 'pNInz6ob78DQ3FnoDB', name: 'Rachel' },
  ta: { id: '5qApY1BkLwFxuDa2K6dX', name: 'Anjali' },
  es: { id: 'gD3CwWQJqCN4XKjMWoGs', name: 'Sofia' },
  de: { id: 'W8xi8E0MQ7dMTGrxu6dS', name: 'Lena' },
  fr: { id: 'CRDBDmtRMJLF4Zxz4QdZ', name: 'Clara' },
};

let ElevenVoice = voiceMap[lang] || voiceMap.nb;
if (voiceId && voiceId.includes('eleven')) {
  ElevenVoice = { id: voiceId, name: 'Custom' };
}

const tts_type = item.tts_type || 'elevenlabs';
const tts_config = {
  type: tts_type,
  voice: ElevenVoice,
  use_premium: tts_type === 'elevenlabs'
};

console.log('🎤 TTS:', tts_config);

return [{ json: { ...item, tts_config } }];

const item = items[0].json;
const videoId = item.video_id;
const tts = item.tts_config || { type: 'elevenlabs' };
const voice = tts.voice || { id: 'CwhRBW8gmZU9ZJ8eXARK', name: 'Pernille' };

let rawText = '';
if (item.scenes && Array.isArray(item.scenes)) {
  rawText = item.scenes.map(s => s.narration || '').filter(Boolean).join('. ');
} else {
  rawText = item.topic || item.title || 'VideoMill video';
}

const cleanText = rawText.replace(/[\"'`$\\]/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 2000);

if (tts.type === 'elevenlabs') {
  return [{ json: { 
    ...item, 
    voice_method: 'elevenlabs',
    voice_id: voice.id,
    text: cleanText,
    engine: 'elevenlabs'
  }}];
} else {
  const edgeVoice = voice.name + 'Neural';
  return [{ json: { 
    ...item, 
    voice_method: 'edge',
    voice_id: edgeVoice,
    text: cleanText,
    engine: 'edge-tts'
  }}];
}

const item = items[0].json;
const videoId = item.video_id;

if (item.voice_method === 'elevenlabs') {
  return [{ json: { ...item, eleven_api_call: true }}];
} else {
  return [{ json: { ...item, edge_call: true }}];
}

const item = items[0].json;
const video = item.scenes || [];

console.log(`🎬 ${video.length} scener å prosessere`);

if (video.length === 0) {
  throw new Error('Ingen scener funnet');
}

return video.map((scene, index) => ({
  json: {
    ...item,
    scene,
    batchIndex: index,
    duration_seconds: scene.duration_seconds || 5,
    search_query: (scene.search_keywords && scene.search_keywords[0]) || item.topic || 'nature',
  }
}));

const videos = $input.first().json.videos || [];
if (!videos.length) return [{ json: { clip_url: null, clip_id: null } }];
const best = videos[0];
const hdFile = best.video_files.find(f => f.quality === 'hd') || best.video_files[0];
return [{ json: { clip_url: hdFile.link, clip_id: best.id } }];

const item = items[0].json;
const aspect = item.aspect_ratio || '9:16';
const dims = aspect === '16:9' ? '1920x1080' : (aspect === '1x1' ? '1080x1080' : '1080x1920');
const videoId = item.video_id || 'unknown';
const dir = `/workspace/video_assets/${videoId}`;

return [{ json: { ...item, dims, dir } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const duration = item.duration_seconds || 5;
const dims = item.dims || '1080x1920';
const dir = item.dir || `/workspace/video_assets/${videoId}`;

try { execSync(`mkdir -p ${dir}/scenes`, { shell: '/bin/bash' }); } catch {}

if (!item.clip_url) {
  const cmd = `ffmpeg -y -f lavfi -i color=c=black:size=${dims}:rate=30 -t ${duration} -c:v libx264 -preset fast ${dir}/scenes/scene_${item.batchIndex}.mp4`;
  try { execSync(cmd, { encoding: 'utf-8', timeout: 60000, shell: '/bin/bash', stdio: 'ignore' }); } catch {}
  return [{ json: { ...item, clip_generated: 'black', scene_path: `${dir}/scenes/scene_${item.batchIndex}.mp4` } }];
}

const cmd = `ffmpeg -y -i "${item.clip_url}" -t ${duration} -vf "scale=${dims.split('x')[0]}:${dims.split('x')[1]}:force_original_aspect_ratio=decrease,pad=${dims}:(ow-iw)/2:(oh-ih)/2" -c:v libx264 -preset fast -an ${dir}/scenes/scene_${item.batchIndex}.mp4`;
try {
  execSync(cmd, { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash', stdio: 'ignore' });
  return [{ json: { ...item, clip_generated: 'ok', scene_path: `${dir}/scenes/scene_${item.batchIndex}.mp4` } }];
} catch(e) {
  console.log('FFmpeg feilet:', e.message);
  return [{ json: { ...item, clip_generated: 'failed' } }];
}

const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;

const files = (() => {
  try {
    const fs = require('fs');
    return fs.readdirSync(`${dir}/scenes`).filter(f => f.endsWith('.mp4'));
  } catch { return []; }
})();

if (files.length === 0) throw new Error('Ingen scener funnet');

files.sort((a, b) => {
  const ai = parseInt(a.replace('scene_', '').replace('.mp4', ''));
  const bi = parseInt(b.replace('scene_', '').replace('.mp4', ''));
  return ai - bi;
});

console.log(`🎬 Slår sammen ${files.length} scener`);

return [{ json: { ...item, scene_files: files, count: files.length } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;
const files = item.scene_files || [];

const listFile = `${dir}/filelist.txt`;
const fileContent = files.map(f => `file '${dir}/scenes/${f}'`).join('\n');

try { execSync(`echo "${fileContent}" > ${listFile}`, { shell: '/bin/bash' }); } catch {}

const cmd = `ffmpeg -y -f concat -safe 0 -i ${listFile} -c copy ${dir}/concat.mp4`;
try {
  execSync(cmd, { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash', stdio: 'ignore' });
  return [{ json: { ...item, concat: 'ok' } }];
} catch(e) {
  throw new Error('Concat feilet: ' + e.message);
}

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;

const hasVoice = item.voice_method;
if (hasVoice) {
  const cmd = `ffmpeg -y -i ${dir}/concat.mp4 -i ${dir}/voiceover.mp3 -c:v copy -c:a aac -shortest ${dir}/merged.mp4`;
  try {
    execSync(cmd, { encoding: 'utf-8', timeout: 60000, shell: '/bin/bash', stdio: 'ignore' });
    return [{ json: { ...item, merged: 'ok' } }];
  } catch {}
}

return [{ json: { ...item, merged: 'skipped' } }];

const item = items[0].json;
const hasMusic = item.include_music !== false;
const musicService = item.music_service || 'epidemic';

if (!hasMusic) return [{ json: { ...item, music: 'disabled' } }];

if (musicService === 'epidemic') {
  return [{ json: { ...item, music: 'epidemic_pending' } }];
} else {
  return [{ json: { ...item, music: 'none' } }];
}

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;
const aspect = item.aspect_ratio || '9:16';

const baseFile = item.merged === 'ok' ? 'merged.mp4' : 'concat.mp4';

const formats = [
  { ratio: '9:16', out: 'final_9x16.mp4', wh: '1080:1920' },
  { ratio: '16:9', out: 'final_16x9.mp4', wh: '1920:1080' },
  { ratio: '1x1', out: 'final_1x1.mp4', wh: '1080:1080' }
];

for (const f of formats) {
  if (f.ratio === aspect || aspect === 'all') {
    const cmd = `ffmpeg -y -i ${dir}/${baseFile} -vf "scale=${f.wh}:force_original_aspect_ratio=decrease,pad=${f.wh}:(ow-iw)/2:(oh-ih)/2" -c copy ${dir}/${f.out}`;
    try { execSync(cmd, { encoding: 'utf-8', timeout: 60000, shell: '/bin/bash', stdio: 'ignore' }); } catch {}
  }
}

return [{ json: { ...item, scaled: 'ok' } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const userId = item.user_id || 'default';
const dir = `/workspace/video_assets/${videoId}`;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const files = [
  { name: 'final_9x16.mp4', key: 'video_url_9x16' },
  { name: 'final_16x9.mp4', key: 'video_url_16x9' },
  { name: 'final_1x1.mp4', key: 'video_url_1x1' }
];

const uploaded = {};

for (const f of files) {
  const path = `${dir}/${f.name}`;
  try {
    execSync(`test -f ${path}`, { shell: '/bin/bash' });
    const storagePath = `${userId}/${videoId}/${f.name}`;
    execSync(`curl -sf -X POST "${supabaseUrl}/storage/v1/object/videos/${storagePath}" -H "Authorization: Bearer ${serviceKey}" -H "Content-Type: video/mp4" --data-binary @"${path}"`, { encoding: 'utf-8', timeout: 300000 });
    uploaded[f.key] = `${supabaseUrl}/storage/v1/object/public/videos/${storagePath}`;
  } catch(e) {
    console.log(`Upload ${f.name} feilet:`, e.message);
  }
}

return [{ json: { ...item, ...uploaded, uploaded: true } }];

const videoId = items[0].json.video_id || 'unknown';
const dir = `/workspace/video_assets/${videoId}`;

try {
  require('child_process').execSync(`rm -rf ${dir}`, { shell: '/bin/bash', timeout: 10000 });
  return [{ json: { cleanup: 'done' } }];
} catch {
  return [{ json: { cleanup: 'failed' } }];
}

const xml = $input.first().json.data || '';
const titles = [...xml.matchAll(/<title>([^<]+)<\/title>/g)].map(m => m[1]).filter(t => t !== 'YouTube').slice(0, 10);

return [{ json: { titles: titles.join('\n'), count: titles.length } }];

