const content = $input.first().json.choices?.[0]?.message?.content || '[]';
let trends = [];
try { trends = JSON.parse(content); } catch {
  try { trends = JSON.parse(content.match(/\[[\s\S]*\]/)[0]); } catch { trends = []; }
}
return trends.map(t => ({ json: t }));

const videos = $input.all().map(i => i.json).filter(v => {
  const updated = new Date(v.updated_at || v.created_at);
  return Date.now() - updated.getTime() > 30 * 60 * 1000;
});

if (videos.length === 0) {
  return [{ json: { status: 'ingen_stuck', count: 0 } }];
}

const results = videos.map(v => ({ json: { video_id: v.id, action: 'retry', title: v.title } }));
console.log(`🐕 Watchdog: ${videos.length} videoer stuck`);
return results;

