parameters.jsCode:
const item = items[0].json;
const topic = item.topic || item.title || 'Video';
const hashtags = item.hashtags || [];

const prompt = `Lag en kort YouTube-beskrivelse for denne videoen: ${topic}. Hashtags: ${hashtags.join(' ')}. Maks 150 ord.`;

return [{ json: { ...item, prompt } }];

const content = $input.first().json.choices?.[0]?.message?.content || '';
const item = $input.first().json;
const videoId = item.video_id;

return [{ json: { ...item, promo_text: content } }];

const item = items[0].json;
const musicEnabled = String($env.MUSIC_ENABLED || 'false').toLowerCase() === 'true';

if (!musicEnabled) {
  return [{ json: { ...item, music_added: false, music_skip: 'MUSIC_ENABLED=false' } }];
}

const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;

try {
  require('child_process').execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
} catch {}

const musicUrl = 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3';

try {
  require('child_process').execSync(`wget -q -O ${dir}/music.mp3 "${musicUrl}"`, { shell: '/bin/bash', timeout: 30000 });
  require('child_process').execSync(`ffmpeg -y -i ${dir}/merged.mp4 -i ${dir}/music.mp3 -filter_complex "[1:a]volume=0.1[m];[0:a][m]amix=inputs=2:duration=first[a]" -map 0:v -map "[a]" -c:v copy -c:a aac ${dir}/final_music.mp4`, { shell: '/bin/bash', timeout: 120000 });
  require('child_process').execSync(`mv ${dir}/final_music.mp4 ${dir}/merged.mp4`, { shell: '/bin/bash' });
  return [{ json: { ...item, music_added: true } }];
} catch(e) {
  console.log('Musikk feilet:', e.message);
  return [{ json: { ...item, music_added: false, music_error: e.message } }];
}

const item = items[0].json;
const captionsEnabled = String($env.CAPTIONS_ENABLED || 'false').toLowerCase() === 'true';

if (!captionsEnabled) {
  return [{ json: { ...item, captions_added: false } }];
}

const videoId = item.video_id;
const scenes = item.scenes || [];
if (!scenes.length) return [{ json: { ...item, captions_added: false } }];

const dir = `/workspace/video_assets/${videoId}`;
let srt = '';
let t = 0;

scenes.forEach((s, i) => {
  const dur = s.duration_seconds || s.duration || 5;
  const ts = d => {
    const ms = Math.round((d % 1) * 1000);
    const sec = Math.floor(d) % 60;
    const min = Math.floor(d / 60) % 60;
    const hr = Math.floor(d / 3600);
    return String(hr).padStart(2,'0') + ':' + String(min).padStart(2,'0') + ':' + String(sec).padStart(2,'0') + ',' + String(ms).padStart(3,'0');
  };
  srt += (i+1) + '\n' + ts(t) + ' --> ' + ts(t+dur) + '\n' + (s.narration||'').substring(0,80) + '\n\n';
  t += dur;
});

try {
  require('fs').writeFileSync(dir + '/subs.srt', srt);
  require('child_process').execSync('ffmpeg -y -i ' + dir + '/merged.mp4 -vf "subtitles=' + dir + '/subs.srt:force_style=FontSize=18,PrimaryColour=&Hffffff" -c:a copy ' + dir + '/final_captions.mp4', { shell: '/bin/bash', timeout: 120000 });
  require('child_process').execSync('mv ' + dir + '/final_captions.mp4 ' + dir + '/merged.mp4', { shell: '/bin/bash' });
  return [{ json: { ...item, captions_added: true } }];
} catch(e) {
  console.log('Captions feilet:', e.message);
  return [{ json: { ...item, captions_added: false } }];
}

const item = items[0].json;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

if (!item.is_series || !item.episode_id) {
  return [{ json: { ...item, episode_updated: false, skip: 'not_series' } }];
}

try {
  const result = await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/episodes?id=eq.' + item.episode_id,
    headers: { apikey: serviceKey, Authorization: 'Bearer ' + serviceKey, 'Content-Type': 'application/json', Prefer: 'return=minimal' },
    body: { status: 'complete', video_id: item.video_id, video_url: item.video_url_16x9 || item.video_url_9x16 || '' },
    json: true
  });
  return [{ json: { ...item, episode_updated: true } }];
} catch(e) {
  console.log('Episode update feilet:', e.message);
  return [{ json: { ...item, episode_updated: false } }];
}

const item = items[0].json;
const supabaseUrl = $env.SUPABASE_URL;
const autoPublish = String($env.AUTO_PUBLISH || 'false').toLowerCase() === 'true';

if (!autoPublish) {
  return [{ json: { ...item, youtube_skip: 'AUTO_PUBLISH not enabled' } }];
}

const videoUrl = item.video_url_16x9 || item.video_url_9x16 || '';
if (!videoUrl || !item.video_id) {
  return [{ json: { ...item, youtube_skip: 'no_video_url' } }];
}

try {
  const fnUrl = supabaseUrl.split('/rest/v1')[0] + '/functions/v1/youtube-upload';
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: fnUrl,
    headers: { 'Content-Type': 'application/json', 'X-Service-Key': $env.INTERNAL_SERVICE_KEY || '' },
    body: {
      user_id: item.user_id,
      video_id: item.video_id,
      video_url: videoUrl,
      title: item.title || item.topic || 'VideoMill Video',
      description: (item.scenes || []).map(s => s.narration || '').join(' ').substring(0, 500),
      tags: item.hashtags || []
    },
    json: true
  });
  return [{ json: { ...item, youtube_result: result } }];
} catch(e) {
  console.log('YouTube upload feilet:', e.message);
  return [{ json: { ...item, youtube_error: e.message } }];
}
